      apb_ck.PWDATA <= data_t'(data);
//      ##1
	apb_ck.PENABLE <= '1;
//      do ##1; while (!apb_ck.PREADY);
      apb_ck.PSEL <= '0;
      apb_ck.PENABLE <= '0 ;
   endtask

   task read(int unsigned addr, output int unsigned data);
//      ##0
